import React, { useState, useEffect } from 'react';
import { supabase } from '../services/supabaseClient';
import { 
  Target, Plus, Trash2, ChevronLeft, ChevronRight, 
  DollarSign, TrendingDown, Star, X 
} from 'lucide-react';
import '../styles/Metas.css';

const Metas = () => {
  const [loading, setLoading] = useState(false);
  const [mes, setMes] = useState(new Date().getMonth() + 1);
  const [ano, setAno] = useState(new Date().getFullYear());
  const [categorias, setCategorias] = useState([]);
  const [metasExistentes, setMetasExistentes] = useState([]);
  const [tabAtiva, setTabAtiva] = useState('despesa');
  const [showModal, setShowModal] = useState(false);
  
  const [novaMetaPessoal, setNovaMetaPessoal] = useState({ nome: '', valor: '' });

  useEffect(() => {
    carregarDados();
  }, [mes, ano]);

  async function carregarDados() {
    setLoading(true);
    // Buscamos categorias e metas (fazendo o join para pegar o nome da categoria na meta)
    const { data: cats } = await supabase.from('categorias').select('*').order('nome');
    const { data: mtd } = await supabase
      .from('metas')
      .select(`*, categorias(nome, cor)`)
      .eq('mes_referencia', mes)
      .eq('ano_referencia', ano);
    
    setCategorias(cats || []);
    setMetasExistentes(mtd || []);
    setLoading(false);
  }

  const handleSalvarMeta = async (categoriaId, valor, tipo) => {
    const { data: { user } } = await supabase.auth.getUser();
    
    const metaData = {
      user_id: user.id,
      categoria_id: categoriaId,
      valor_objetivo: parseFloat(valor) || 0,
      tipo_meta: tipo,
      mes_referencia: mes,
      ano_referencia: ano
    };

    const { error } = await supabase
      .from('metas')
      .upsert(metaData, { onConflict: 'categoria_id, mes_referencia, ano_referencia' });

    if (error) alert("Erro ao salvar meta: " + error.message);
    else carregarDados();
  };

  const criarMetaPessoalCompleta = async () => {
    if (!novaMetaPessoal.nome || !novaMetaPessoal.valor) return;
    
    try {
      const { data: { user } } = await supabase.auth.getUser();

      // 1. Criar a categoria do tipo 'pessoal' primeiro
      const { data: newCat, error: catError } = await supabase
        .from('categorias')
        .insert({ 
          nome: novaMetaPessoal.nome, 
          tipo: 'pessoal', 
          cor: '#8b5cf6',
          user_id: user.id 
        })
        .select()
        .single();

      if (catError) throw catError;

      // 2. Criar a meta vinculada a essa nova categoria
      await handleSalvarMeta(newCat.id, novaMetaPessoal.valor, 'pessoal');
      
      setNovaMetaPessoal({ nome: '', valor: '' });
      setShowModal(false);
    } catch (error) {
      alert("Erro ao criar objetivo: " + error.message);
    }
  };

  const deletarMeta = async (id) => {
    if (window.confirm("Deseja excluir esta meta?")) {
      await supabase.from('metas').delete().eq('id', id);
      carregarDados();
    }
  };

  const getValorMeta = (catId) => {
    return metasExistentes.find(m => m.categoria_id === catId)?.valor_objetivo || '';
  };

  return (
    <div className="metas-container fade-in">
      <header className="metas-header">
        <div className="titulo-secao">
          <Target size={28} color="#4361ee" />
          <h1>Planejamento</h1>
        </div>
        
        <div className="seletor-periodo">
          <button onClick={() => setMes(m => m === 1 ? 12 : m - 1)}><ChevronLeft size={20} /></button>
          <span>{new Intl.DateTimeFormat('pt-BR', { month: 'long' }).format(new Date(ano, mes - 1))} {ano}</span>
          <button onClick={() => setMes(m => m === 12 ? 1 : m + 1)}><ChevronRight size={20} /></button>
        </div>
      </header>

      <nav className="metas-tabs">
        <button className={tabAtiva === 'despesa' ? 'active' : ''} onClick={() => setTabAtiva('despesa')}>
          <TrendingDown size={18} /> Gastos
        </button>
        <button className={tabAtiva === 'provento' ? 'active' : ''} onClick={() => setTabAtiva('provento')}>
          <DollarSign size={18} /> Receitas
        </button>
        <button className={tabAtiva === 'pessoal' ? 'active' : ''} onClick={() => setTabAtiva('pessoal')}>
          <Star size={18} /> Objetivos
        </button>
      </nav>

      <div className="metas-content">
        {tabAtiva !== 'pessoal' ? (
          <div className="grid-metas-cats">
            {categorias.filter(c => c.tipo === tabAtiva).map(cat => (
              <div key={cat.id} className="input-meta-group">
                <div className="info-cat">
                  <div className="dot" style={{backgroundColor: cat.cor}}></div>
                  <label>{cat.nome}</label>
                </div>
                <div className="input-wrapper">
                  <span>R$</span>
                  <input 
                    type="number" 
                    placeholder="0,00"
                    defaultValue={getValorMeta(cat.id)}
                    onBlur={(e) => handleSalvarMeta(cat.id, e.target.value, tabAtiva)}
                  />
                </div>
              </div>
            ))}
          </div>
        ) : (
          <div className="metas-pessoais-list">
            {metasExistentes.filter(m => m.tipo_meta === 'pessoal').map(m => (
              <div key={m.id} className="item-pessoal">
                <div className="item-pessoal-info">
                   <div className="dot" style={{backgroundColor: m.categorias?.cor || '#8b5cf6'}}></div>
                   <span>{m.categorias?.nome}</span>
                </div>
                <strong>R$ {Number(m.valor_objetivo).toLocaleString('pt-BR', {minimumFractionDigits: 2})}</strong>
                <button onClick={() => deletarMeta(m.id)}><Trash2 size={18} /></button>
              </div>
            ))}
            {metasExistentes.filter(m => m.tipo_meta === 'pessoal').length === 0 && (
                <p className="cat-empty">Nenhum objetivo definido para este mês.</p>
            )}
          </div>
        )}
      </div>

      {/* Botão Flutuante (FAB) - Apenas na aba pessoal */}
      {tabAtiva === 'pessoal' && (
        <button className="cat-fab" onClick={() => setShowModal(true)}>
          <Plus size={28} />
        </button>
      )}

      {/* Modal para Novo Objetivo */}
      {showModal && (
        <div className="modal-overlay">
          <div className="cat-modal fade-in">
            <div className="cat-modal-header">
              <h3>Novo Objetivo</h3>
              <button onClick={() => setShowModal(false)}><X size={20} /></button>
            </div>
            <div className="cat-modal-form">
              <div className="cat-input-box">
                <label>Nome do Objetivo</label>
                <input 
                  type="text" 
                  placeholder="Ex: Viagem, Reserva..." 
                  value={novaMetaPessoal.nome}
                  onChange={e => setNovaMetaPessoal({...novaMetaPessoal, nome: e.target.value})}
                />
              </div>
              <div className="cat-input-box">
                <label>Valor Alvo</label>
                <div className="cat-money-input-wrapper">
                  <span className="prefix">R$</span>
                  <input 
                    type="number" 
                    placeholder="0,00"
                    value={novaMetaPessoal.valor}
                    onChange={e => setNovaMetaPessoal({...novaMetaPessoal, valor: e.target.value})}
                  />
                </div>
              </div>
              <button className="btn-cat-save" onClick={criarMetaPessoalCompleta}>
                Criar Objetivo
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Metas;
